import{_ as e,o as t,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F10: 成本結構與經營槓桿門檻 - 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F10_成本結構與經營槓桿門檻_財務分析專家.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F10_成本結構與經營槓桿門檻_財務分析專家.md"}'),r={name:"審計報告庫/財務審計/6257_矽格/20260430/F10_成本結構與經營槓桿門檻_財務分析專家.md"};function o(_,a,n,h,c,s){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="f10-成本結構與經營槓桿門檻-財務分析專家-審計報告" tabindex="-1">F10: 成本結構與經營槓桿門檻 - 財務分析專家 審計報告 <a class="header-anchor" href="#f10-成本結構與經營槓桿門檻-財務分析專家-審計報告" aria-label="Permalink to &quot;F10: 成本結構與經營槓桿門檻 - 財務分析專家 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>公司的成本結構為何？固定成本與變動成本的比例如何影響其規模經濟？企業目前的「獲利擴張臨界點」在那裡？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li>固定成本佔營收 39.9%，DOL 3.87。DOL 近 4 倍，獲利對營收高度敏感，營收回落逾 25% 即逼近虧損。</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li>固定成本佔營收三年自 49.2% 降至 39.9%，營業利益率 13.4%→20.3%。</li><li>折舊連續兩年負增長與未來百億級資本支出背離，新產能折舊轉入後固定成本佔比恐回升，若 AI/ASIC 測試延遲，獲利品質將受侵蝕。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-營運成本習性拆解" tabindex="-1">1. 營運成本習性拆解 <a class="header-anchor" href="#_1-營運成本習性拆解" aria-label="Permalink to &quot;1. 營運成本習性拆解&quot;">​</a></h3><ul><li>固定成本佔營收 39.9%，折舊佔固定成本 51.7%。折舊連續兩年下降（-4.5%、-5.4%）與中興三廠擴建背離，合理推斷為舊設備已提足折舊、新設備尚未轉入（2026Q4 完工），但不排除折舊年限拉長的財務粉飾可能。</li></ul><h3 id="_2-規模經濟臨界檢核" tabindex="-1">2. 規模經濟臨界檢核 <a class="header-anchor" href="#_2-規模經濟臨界檢核" aria-label="Permalink to &quot;2. 規模經濟臨界檢核&quot;">​</a></h3><ul><li>損益平衡點 129.9 億，實際營收 195.9 億，安全邊際 33.7%。中興三廠量產後（滿載月貢獻 3 億營收），若稼動率爬升，OPM 有進一步擴張空間。</li></ul><h3 id="_3-景氣承壓測試" tabindex="-1">3. 景氣承壓測試 <a class="header-anchor" href="#_3-景氣承壓測試" aria-label="Permalink to &quot;3. 景氣承壓測試&quot;">​</a></h3><ul><li>營收 -20% → OI 跌 59.4%；營收 -30% → OI 跌 89.1%。-30% 情境下營收 137 億，逼近損益平衡，淨利趨零。封測產業景氣循環 15-25%，正常修正可承受，2008/2020 等級需求驟降將面臨嚴峻挑戰。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：折舊政策疑雲</strong>。折舊費用連續兩年下降（-4.5%、-5.4%），與公司積極擴產（2025 capex 47 億、2026 預算 59 億）形成背離。若折舊年限被拉長（例如從 5 年延至 7 年），將人為壓低費用、膨脹短期獲利。此為「財務粉飾」的經典信號，投資人應比對歷年折舊年限假設變動。</li><li><strong>空頭風險二：新產能消化壓力</strong>。中興三廠（2026Q4 完工）與湖口二廠（2026H2 加入）將新增大量固定成本。若 AI/ASIC 測試需求不如預期，新設備折舊將推升固定成本佔比，安全邊際將被壓縮。以 2026 年 capex 59 億估算，年增折舊約 8-10 億，固定成本佔營收可能回升至 42-44%，侵蝕當前槓桿紅利。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — 營收/營業利益/折舊/攤銷/人事費用/現金流數據完整取得，涵蓋 2023Q1-2025Q4</li><li><strong>年報</strong>: OK — 2024_Q4_6257_合併.pdf（費用性質分類、附註 P.40/P.53）、2025_Q4_6257_合併.pdf（最新年度數據）</li><li><strong>關鍵核對碼</strong>: 2025 營收 19,587,196仟元 / 營業利益 3,967,552仟元 / 折舊 3,964,582仟元 / 人事 5,064,170仟元</li></ul>',19)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
